#include<bits/stdc++.h>
using namespace std;
long long t,n,L,a[500010],cnt[500010];
int main()
{
    scanf("%lld",&t);
    while(t--)
    {
        scanf("%lld%lld",&n,&L);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&a[i]);
        }
        long long r=0,ans=0;
        for(long long l=1;l<=n;l++)
        {
            while((r<l||a[r]!=a[r+1])&&r<n)
            {
                r++;
                if(r>=l+L-1)
                {
                    cnt[a[r]]++;
                }
            }
            ans+=max(0ll,r-(l+L-1)+1-cnt[a[l]]);
            if(r>=l+L-1)
            {
                cnt[a[l+L-1]]--;
            }
        }
        printf("%lld\n",ans);
    }
    return 0;
}
